#include <stdio.h>
#include <stdint.h>

static uint64_t sum_lsb(uint64_t N) {
    uint64_t total = 0;
    for (uint64_t pow = 1; pow <= N; pow <<= 1) {
        uint64_t cnt = N / pow - N / (pow << 1);
        total += pow * cnt;
    }
    return total - 1; // remove lsb(1)
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint64_t N;
        scanf("%llu", &N);
        if ((N & (N - 1)) == 0) {
            printf("-1\n");
        } else {
            printf("%llu\n", sum_lsb(N));
        }
    }
    return 0;
}

