import sys

def sum_lsb(N: int) -> int:
    total = 0
    pow = 1
    while pow <= N:
        cnt = N // pow - N // (pow << 1)
        total += pow * cnt
        pow <<= 1
    return total - 1  # exclude lsb(1)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        N = int(data[idx]); idx += 1
        if N & (N - 1) == 0:
            out.append('-1')
        else:
            out.append(str(sum_lsb(N)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

